755       return nullptr;
756 
757     LoadAlignment = std::min(LoadAlignment, LI->getAlign());
758 
759     // If the PHI is of volatile loads and the load block has multiple
760     // successors, sinking it would remove a load of the volatile value from
761     // the path through the other successor.
