635   // Add all operands to the new PHIs.
636   if (HasAnyPHIs) {
637     for (auto Incoming : drop_begin(zip(PN.blocks(), PN.incoming_values()))) {
638       BasicBlock *InBB = std::get<0>(Incoming);
639       Value *InVal = std::get<1>(Incoming);
640       GetElementPtrInst *InGEP = cast<GetElementPtrInst>(InVal);
641 
642       for (unsigned Op = 0, E = OperandPhis.size(); Op != E; ++Op)
643         if (PHINode *OpPhi = OperandPhis[Op])
644           OpPhi->addIncoming(InGEP->getOperand(Op), InBB);
645     }
