656 /// Return true if we know that it is safe to sink the load out of the block
657 /// that defines it. This means that it must be obvious the value of the load is
658 /// not changed from the point of the load to the end of the block it is in.
659 ///
660 /// Finally, it is safe, but not profitable, to sink a load targeting a
661 /// non-address-taken alloca.  Doing so will cause us to not promote the alloca
662 /// to a register.
663 static bool isSafeAndProfitableToSinkLoad(LoadInst *L) {
664   BasicBlock::iterator BBI = L->getIterator(), E = L->getParent()->end();
665 
666   for (++BBI; BBI != E; ++BBI)
667     if (BBI->mayWriteToMemory()) {
668       // Calls that only access inaccessible memory do not block sinking the
669       // load.
670       if (auto *CB = dyn_cast<CallBase>(BBI))
671         if (CB->onlyAccessesInaccessibleMemory())
672           continue;
673       return false;
674     }
675 
676   // Check for non-address taken alloca.  If not address-taken already, it isn't
677   // profitable to do this xform.
678   if (AllocaInst *AI = dyn_cast<AllocaInst>(L->getOperand(0))) {
679     bool IsAddressTaken = false;
680     for (User *U : AI->users()) {
681       if (isa<LoadInst>(U)) continue;
682       if (StoreInst *SI = dyn_cast<StoreInst>(U)) {
683         // If storing TO the alloca, then the address isn't taken.
684         if (SI->getOperand(1) == AI) continue;
685       }
686       IsAddressTaken = true;
687       break;
688     }
689 
690     if (!IsAddressTaken && AI->isStaticAlloca())
691       return false;
692   }
693 
694   // If this load is a load from a GEP with a constant offset from an alloca,
695   // then we don't want to sink it.  In its present form, it will be
696   // load [constant stack offset].  Sinking it will cause us to have to
697   // materialize the stack addresses in each predecessor in a register only to
698   // do a shared load from register in the successor.
699   if (GetElementPtrInst *GEP = dyn_cast<GetElementPtrInst>(L->getOperand(0)))
700     if (AllocaInst *AI = dyn_cast<AllocaInst>(GEP->getOperand(0)))
701       if (AI->isStaticAlloca() && GEP->hasAllConstantIndices())
702         return false;
703 
704   return true;
705 }
